import type {
  AdapterCapabilities,
  AdapterCategory,
  AdapterSubscription,
  ConnectionStatus,
  ExchangeAdapter,
  ExchangeConfig,
  HealthMetrics,
  OHLCVCallback,
  OrderbookCallback,
  StatusCallback,
  TickerCallback,
  TradeCallback,
} from '../../types/adapter';
import type { NormalizedOHLCV, NormalizedOrderbook, NormalizedSymbol, NormalizedTick, NormalizedTrade, Timeframe } from '../../types/normalized';
import { createSubscriptionId, parseNumeric } from '../../normalization/pipeline';
import type {
  CacheEntry,
  GeckoOHLCVResponse,
  GeckoPoolAttributes,
  GeckoPoolResource,
  GeckoPoolsResponse,
  GeckoTimeframe,
} from './gecko-terminal-types';

const API_BASE_URL = 'https://api.geckoterminal.com/api/v2';

/** 30 calls/min = 1 call per 2s. We enforce with a sliding window. */
const RATE_LIMIT_MAX_CALLS = 30;
const RATE_LIMIT_WINDOW_MS = 60_000;

/** Default polling interval for subscriptions (15 seconds). */
const DEFAULT_POLL_INTERVAL_MS = 15_000;

/** Cache TTL for responses (30 seconds). */
const CACHE_TTL_MS = 30_000;

/** Default network for pool discovery when none specified. */
const DEFAULT_NETWORK = 'eth';

/** Timeframe mapping from normalized Timeframe to GeckoTerminal parameters. */
const TIMEFRAME_MAP: Partial<Record<Timeframe, { aggregate: number; timeframe: GeckoTimeframe }>> = {
  '1m':  { aggregate: 1,  timeframe: 'minute' },
  '5m':  { aggregate: 5,  timeframe: 'minute' },
  '15m': { aggregate: 15, timeframe: 'minute' },
  '1h':  { aggregate: 1,  timeframe: 'hour' },
  '4h':  { aggregate: 4,  timeframe: 'hour' },
  '12h': { aggregate: 12, timeframe: 'hour' },
  '1d':  { aggregate: 1,  timeframe: 'day' },
};

interface ActiveSubscription {
  readonly id: string;
  readonly symbol: string;
  readonly type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv' | 'status';
  readonly callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback | StatusCallback;
  readonly network: string;
  readonly poolAddress: string;
}

/**
 * GeckoTerminal adapter for on-chain DEX pool data across 250+ chains.
 *
 * REST-only adapter (no WebSocket). Uses polling for subscriptions with a
 * 15-second interval. Enforces 30 calls/min rate limit with an in-memory
 * response cache to minimize API calls.
 */
export class GeckoTerminalAdapter implements ExchangeAdapter {
  readonly exchangeId = 'gecko-terminal' as const;
  readonly displayName = 'GeckoTerminal';
  readonly category: AdapterCategory = 'aggregator';
  readonly capabilities: AdapterCapabilities = {
    realtime: false,
    historicalDepth: '30d',
    orderbook: false,
    trades: true,
    ohlcv: true,
    fundingRates: false,
    openInterest: false,
    liquidations: false,
    defiMetrics: true,
    onChainMetrics: false,
    authenticated: false,
  };

  private baseUrl = API_BASE_URL;
  private network = DEFAULT_NETWORK;
  private readonly subscriptions = new Map<string, ActiveSubscription>();
  private readonly statusCallbacks = new Map<string, StatusCallback>();
  private pollTimer: ReturnType<typeof setInterval> | undefined;
  private connectTime = 0;
  private connectionState: ConnectionStatus = {
    state: 'disconnected',
    latencyMs: 0,
    messagesPerSecond: 0,
    lastMessageAt: 0,
    reconnectAttempt: 0,
    uptime: 0,
  };

  /** Sliding window timestamps for rate limiting. */
  private readonly callTimestamps: number[] = [];

  /** In-memory response cache keyed by URL. */
  private readonly cache = new Map<string, CacheEntry<unknown>>();

  async connect(config: ExchangeConfig): Promise<void> {
    if (config.restUrl) {
      this.baseUrl = config.restUrl;
    }
    if (config.extra?.['network']) {
      this.network = config.extra['network'];
    }
    this.connectTime = Date.now();
    this.updateState('connected');

    this.pollTimer = setInterval(() => {
      this.pollSubscriptions().catch(() => {
        // Polling errors are non-fatal; state is updated in fetchWithRateLimit
      });
    }, DEFAULT_POLL_INTERVAL_MS);
  }

  async disconnect(): Promise<void> {
    if (this.pollTimer !== undefined) {
      clearInterval(this.pollTimer);
      this.pollTimer = undefined;
    }
    this.subscriptions.clear();
    this.cache.clear();
    this.callTimestamps.length = 0;
    this.updateState('disconnected');
    this.statusCallbacks.clear();
  }

  getStatus(): ConnectionStatus {
    return { ...this.connectionState, uptime: this.getUptime() };
  }

  getHealthMetrics(): HealthMetrics {
    const status = this.getStatus();
    const uptimePercent = status.uptime > 0
      ? Math.min(100, (status.uptime / (status.uptime + status.reconnectAttempt * 5)) * 100)
      : 0;
    return {
      connected: status.state === 'connected',
      latencyMs: status.latencyMs,
      messagesPerSecond: status.messagesPerSecond,
      uptimePercent,
      lastMessageAt: status.lastMessageAt,
      errorRate: 0,
      circuitBreakerState: 'closed',
    };
  }

  onStatusChange(callback: StatusCallback): AdapterSubscription {
    const id = createSubscriptionId('gecko-terminal', 'status', '_global');
    this.statusCallbacks.set(id, callback);
    return {
      id,
      symbol: '_global',
      type: 'status',
      dispose: () => { this.statusCallbacks.delete(id); },
    };
  }

  subscribeTicker(symbol: string, callback: TickerCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'ticker', callback);
  }

  subscribeOrderbook(_symbol: string, _depth: number, _callback: OrderbookCallback): AdapterSubscription {
    throw new Error('GeckoTerminal does not support order books for AMM pools');
  }

  subscribeTrades(symbol: string, callback: TradeCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'trades', callback);
  }

  subscribeOHLCV(symbol: string, _timeframe: Timeframe, callback: OHLCVCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'ohlcv', callback);
  }

  async getCandles(symbol: string, timeframe: Timeframe, _from: number, _to: number): Promise<NormalizedOHLCV[]> {
    const mapping = TIMEFRAME_MAP[timeframe];
    if (!mapping) {
      throw new Error(`Unsupported timeframe for GeckoTerminal: ${timeframe}`);
    }

    const { network, poolAddress } = this.parseSymbol(symbol);
    const url = `${this.baseUrl}/networks/${network}/pools/${poolAddress}/ohlcv/${mapping.timeframe}?aggregate=${mapping.aggregate}&limit=1000`;

    const response = await this.fetchWithRateLimit<GeckoOHLCVResponse>(url);
    const ohlcvList = response.data.attributes.ohlcv_list;

    return ohlcvList.map(item => ({
      timestamp: item[0] * 1000,
      open: item[1],
      high: item[2],
      low: item[3],
      close: item[4],
      volume: item[5],
      quoteVolume: item[5],
      tradeCount: 0,
      closed: true,
    }));
  }

  async getOrderbookSnapshot(_symbol: string, _depth: number): Promise<NormalizedOrderbook> {
    throw new Error('GeckoTerminal does not support order books for AMM pools');
  }

  async getRecentTrades(_symbol: string, _limit: number): Promise<NormalizedTrade[]> {
    return [];
  }

  async getSymbols(): Promise<NormalizedSymbol[]> {
    const url = `${this.baseUrl}/networks/${this.network}/pools?page=1`;
    const response = await this.fetchWithRateLimit<GeckoPoolsResponse>(url);

    return response.data.map(pool => this.normalizePoolToSymbol(pool, this.network));
  }

  // ---------------------------------------------------------------------------
  // Private helpers
  // ---------------------------------------------------------------------------

  private addSubscription(
    symbol: string,
    type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv',
    callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback,
  ): AdapterSubscription {
    const id = createSubscriptionId('gecko-terminal', type, symbol);
    const { network, poolAddress } = this.parseSymbol(symbol);
    const sub: ActiveSubscription = { id, symbol, type, callback, network, poolAddress };
    this.subscriptions.set(id, sub);

    return {
      id,
      symbol,
      type,
      dispose: () => { this.subscriptions.delete(id); },
    };
  }

  private async pollSubscriptions(): Promise<void> {
    const tickerSubs = Array.from(this.subscriptions.values()).filter(s => s.type === 'ticker');
    for (const sub of tickerSubs) {
      const url = `${this.baseUrl}/networks/${sub.network}/pools/${sub.poolAddress}`;
      const response = await this.fetchWithRateLimit<{ data: GeckoPoolResource }>(url);
      const pool = response.data;
      const tick = this.normalizePoolToTick(pool, sub.symbol);
      (sub.callback as TickerCallback)(tick);
    }
  }

  private normalizePoolToTick(pool: GeckoPoolResource, symbol: string): NormalizedTick {
    const attrs = pool.attributes;
    const price = parseNumeric(attrs.base_token_price_usd ?? undefined);
    const volume24h = parseNumeric(attrs.volume_usd.h24 ?? undefined);
    const priceChangePct = parseNumeric(attrs.price_change_percentage.h24 ?? undefined);

    return {
      symbol,
      lastPrice: price,
      priceChange: price * (priceChangePct / 100),
      priceChangePercent: priceChangePct,
      high24h: price,
      low24h: price,
      volume24h,
      quoteVolume24h: volume24h,
      timestamp: Date.now(),
      bestBid: price,
      bestBidQty: 0,
      bestAsk: price,
      bestAskQty: 0,
    };
  }

  private normalizePoolToSymbol(pool: GeckoPoolResource, network: string): NormalizedSymbol {
    const attrs = pool.attributes;
    const nameParts = attrs.name.split(' / ');
    const base = nameParts[0]?.trim() || 'UNKNOWN';
    const quote = nameParts[1]?.trim() || 'UNKNOWN';
    const reserveUsd = parseNumeric(attrs.reserve_in_usd ?? undefined);

    return {
      symbol: `${base}/${quote}`,
      base,
      quote,
      exchangeSymbol: attrs.address,
      exchangeId: 'gecko-terminal' as const,
      type: 'dex-pool' as const,
      pricePrecision: 18,
      quantityPrecision: 18,
      minQuantity: 0,
      tickSize: 1e-18,
      active: reserveUsd > 0,
      contractAddress: attrs.address,
      chain: network,
      feeTier: this.extractFeeTier(attrs),
    };
  }

  private extractFeeTier(attrs: GeckoPoolAttributes): number | undefined {
    // GeckoTerminal does not always return fee tier; return undefined when absent
    const name = attrs.name || '';
    const feeMatch = name.match(/(\d+(?:\.\d+)?)%/);
    if (feeMatch?.[1]) {
      const percent = parseFloat(feeMatch[1]);
      return Math.round(percent * 100); // Convert percent to basis points
    }
    return undefined;
  }

  /**
   * Parse a symbol string into network and pool address.
   * Accepted formats:
   *  - "network:poolAddress" (e.g., "eth:0x88e6a0...")
   *  - Plain pool address (uses this.network)
   */
  private parseSymbol(symbol: string): { network: string; poolAddress: string } {
    const colonIdx = symbol.indexOf(':');
    if (colonIdx > 0) {
      return {
        network: symbol.slice(0, colonIdx),
        poolAddress: symbol.slice(colonIdx + 1),
      };
    }
    return { network: this.network, poolAddress: symbol };
  }

  /**
   * Fetch with rate limiting and caching.
   * Enforces 30 calls/min by checking a sliding window of call timestamps.
   * Caches successful responses for 30 seconds.
   */
  private async fetchWithRateLimit<T>(url: string): Promise<T> {
    // Check cache first
    const cached = this.cache.get(url) as CacheEntry<T> | undefined;
    if (cached && cached.expiresAt > Date.now()) {
      return cached.data;
    }

    // Enforce rate limit
    await this.waitForRateLimit();

    const start = Date.now();
    const response = await fetch(url, {
      headers: { Accept: 'application/json' },
    });

    const latency = Date.now() - start;
    this.connectionState = {
      ...this.connectionState,
      latencyMs: latency,
      lastMessageAt: Date.now(),
    };

    if (!response.ok) {
      if (response.status === 429) {
        this.updateState('error', 'Rate limit exceeded');
      }
      throw new Error(`GeckoTerminal API error: ${response.status} ${response.statusText}`);
    }

    const data = (await response.json()) as T;

    // Cache the response
    this.cache.set(url, { data, expiresAt: Date.now() + CACHE_TTL_MS });

    return data;
  }

  /**
   * Wait until we are below the rate limit threshold.
   * Uses a sliding window of call timestamps to enforce 30 calls/min.
   */
  private async waitForRateLimit(): Promise<void> {
    // Prune timestamps older than the window
    const now = Date.now();
    while (this.callTimestamps.length > 0 && (this.callTimestamps[0] ?? 0) <= now - RATE_LIMIT_WINDOW_MS) {
      this.callTimestamps.shift();
    }

    if (this.callTimestamps.length >= RATE_LIMIT_MAX_CALLS) {
      const oldestInWindow = this.callTimestamps[0] ?? now;
      const waitMs = oldestInWindow + RATE_LIMIT_WINDOW_MS - now + 1;
      await new Promise<void>(resolve => setTimeout(resolve, waitMs));
      // Re-prune after waiting
      const afterWait = Date.now();
      while (this.callTimestamps.length > 0 && (this.callTimestamps[0] ?? 0) <= afterWait - RATE_LIMIT_WINDOW_MS) {
        this.callTimestamps.shift();
      }
    }

    this.callTimestamps.push(Date.now());
  }

  private updateState(state: ConnectionStatus['state'], errorMessage?: string): void {
    this.connectionState = {
      state,
      latencyMs: this.connectionState.latencyMs,
      messagesPerSecond: this.connectionState.messagesPerSecond,
      lastMessageAt: this.connectionState.lastMessageAt,
      errorMessage,
      reconnectAttempt: 0,
      uptime: this.getUptime(),
    };
    for (const callback of this.statusCallbacks.values()) {
      callback(this.connectionState);
    }
  }

  private getUptime(): number {
    if (this.connectTime === 0) return 0;
    return (Date.now() - this.connectTime) / 1000;
  }
}
